cards.solution_code:
import logging

def get_app_logger():
    logger = logging.getLogger('app')
    logger.setLevel(logging.INFO)
    return logger

def log_event(logger, kind, detail):
    msg = f'{kind}: {detail}'
    if kind == 'event':
        logger.info(msg)
    else:
        logger.error(msg)

